// Extract titles from all sources
const hnItems = $('Fetch HN Stories').all();
const redditData = $('Fetch Reddit r/programming').first().json;
const githubData = $('Fetch GitHub Trending').first().json;

// HN titles
const hnTitles = hnItems.map(item => item.json.title || '').filter(Boolean);

// Reddit titles
const redditTitles = (redditData?.data?.children || []).map(c => c.data?.title || '').filter(Boolean);

// GitHub repo names + descriptions
const githubTitles = (githubData?.items || []).map(r => `${r.name} ${r.description || ''}`).filter(Boolean);

// Keyword extraction
const techPattern = /\b(ai|llm|gpt|claude|docker|kubernetes|k8s|rust|python|react|vue|nextjs|typescript|golang|postgres|redis|aws|azure|gcp|devops|cicd|microservices|serverless|blockchain|web3|api|graphql|grpc|wasm|langchain|rag|vector|embedding|agent|copilot|gemini|ollama|llama|mistral|openai|supabase|drizzle|htmx|bun|deno|svelte|tailwind)\b/gi;

function extractKeywords(titles) {
  const matches = titles.join(' ').match(techPattern) || [];
  const freq = {};
  matches.forEach(t => {
    const key = t.toLowerCase();
    freq[key] = (freq[key] || 0) + 1;
  });
  return freq;
}

const sourceKeywords = {
  hackernews: extractKeywords(hnTitles),
  reddit: extractKeywords(redditTitles),
  github: extractKeywords(githubTitles)
};

return [{
  json: {
    sourceKeywords,
    hnTitles: hnTitles.slice(0, 5),
    redditTitles: redditTitles.slice(0, 5),
    githubTitles: githubTitles.slice(0, 5)
  }
}];

// Cross-reference: find keywords appearing in 2+ sources
const { sourceKeywords, hnTitles, redditTitles, githubTitles } = $input.first().json;

// Collect all unique keywords
const allKeywords = new Set();
Object.values(sourceKeywords).forEach(freq => {
  Object.keys(freq).forEach(kw => allKeywords.add(kw));
});

// Find trending (in 2+ sources)
const trending = [];
for (const kw of allKeywords) {
  const sources = Object.keys(sourceKeywords).filter(src =>
    sourceKeywords[src][kw] && sourceKeywords[src][kw] > 0
  );
  if (sources.length >= 2) {
    // Collect sample titles mentioning this keyword
    const allTitles = [...hnTitles, ...redditTitles, ...githubTitles];
    const samples = allTitles
      .filter(t => t.toLowerCase().includes(kw))
      .slice(0, 3);
    trending.push({
      keyword: kw,
      sources,
      source_count: sources.length,
      sample_titles: samples
    });
  }
}

// Sort by source_count desc
trending.sort((a, b) => b.source_count - a.source_count);

return trending.map(t => ({ json: t }));

const items = $input.all();
const count = items.length;
if (count === 0) {
  return [{ json: { message: 'No new trending topics detected today.' } }];
}
const keywords = items.map(i => i.json.keyword || i.json.topic || 'unknown');
const message = `🔥 ${count} trending topic${count > 1 ? 's' : ''} detected:\n${keywords.map(k => `• ${k}`).join('\n')}`;
return [{ json: { message } }];
